SELECT crop_name AS cropName, COUNT(*) AS count, IFNULL(SUM(plant_area), 0) AS totalArea, IFNULL(SUM(actual_yield), 0) AS totalYield FROM herb_crop WHERE deleted = 0
AND user_id = #{userId}
GROUP BY crop_name ORDER BY count DESC

SELECT status, COUNT(*) AS count FROM herb_crop WHERE deleted = 0
AND user_id = #{userId}
GROUP BY status
